#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n); // Read the number of elements

    int v1[n]; // Declare the array
    for (int i = 0; i < n; i++) {
        scanf("%d", &v1[i]); // Read each element of the array
    }

    long long pre[n]; // Declare the prefix sum array
    pre[0] = v1[0]; // Initialize the first element
    for (int i = 1; i < n; i++) {
        pre[i] = pre[i - 1] + v1[i]; // Compute prefix sums
    }

    int q;
    scanf("%d", &q); // Read the number of queries
    while (q--) {
        int n1, n2;
        scanf("%d %d", &n1, &n2); // Read the query indices
        n1--; // Convert to 0-based index
        n2--; // Convert to 0-based index

        // Calculate the sum based on the query indices
        if (n1 == 0) {
            printf("%lld\n", pre[n2]); // Output the sum from start to n2
        } else {
            printf("%lld\n", (pre[n2] - pre[n1 - 1])); // Output the sum from n1 to n2
        }
    }

    printf("\n"); // Print a new line at the end
    return 0; // Return success
}

