const readline = require('readline');

// Create interface for input
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let inputLines = [];
rl.on('line', (line) => {
    inputLines.push(line.trim());
});

rl.on('close', () => {
    // Parse inputs
    let idx = 0;

    const n = parseInt(inputLines[idx++]); // First line: length of array
    const v1 = inputLines[idx++].split(' ').map(Number); // Second line: array elements

    // Create prefix sum array
    const pre = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        pre[i] = v1[i] + (i > 0 ? pre[i - 1] : 0);
    }

    const q = parseInt(inputLines[idx++]); // Third line: number of queries

    // Process queries
    let results = [];
    for (let i = 0; i < q; i++) {
        const [n1, n2] = inputLines[idx++].split(' ').map(Number);
        const l = n1 - 1; // Convert to zero-based index
        const r = n2 - 1; // Convert to zero-based index
        const sum = l === 0 ? pre[r] : pre[r] - pre[l - 1];
        results.push(sum);
    }

    // Print results
    console.log(results.join('\n'));
});
